import { MongoClient } from "mongodb";
import { logger } from "./logger.js";

let _client = null;
let _db = null;
let _connecting = null;

export async function getDb(mongoUri) {
  const uri = String(mongoUri || "").trim();
  if (!uri) return null;
  if (_db) return _db;
  if (_connecting) return _connecting;

  _connecting = (async () => {
    try {
      _client = new MongoClient(uri, { maxPoolSize: 5, ignoreUndefined: true });
      await _client.connect();
      _db = _client.db();
      logger.info("db.connected", { MONGODB_URI_set: true });
      return _db;
    } catch (e) {
      logger.error("db.connect_failed", { err: logger.safeErr(e), MONGODB_URI_set: true });
      _db = null;
      return null;
    } finally {
      _connecting = null;
    }
  })();

  return _connecting;
}

logger.js.content:
import { safeErr } from "./safeErr.js";

function log(level, msg, meta = {}) {
  const out = {
    t: new Date().toISOString(),
    level,
    msg,
    ...meta,
  };
  if (level === "error") console.error(JSON.stringify(out));
  else if (level === "warn") console.warn(JSON.stringify(out));
  else console.log(JSON.stringify(out));
}

export const logger = {
  info: (msg, meta) => log("info", msg, meta),
  warn: (msg, meta) => log("warn", msg, meta),
  error: (msg, meta) => log("error", msg, meta),
  safeErr,
};

